sql:
SELECT COUNT(*) 
FROM trial_outcomes 
WHERE outcome_type = 'Primary' AND outcome_status = 'Completed';

SELECT COUNT(*) AS participant_count
FROM trial_participants
WHERE trial_id = 1;

SELECT AVG(capacity) AS average_capacity
FROM trial_locations
WHERE site_type = 'Hospital';

SELECT outcome_type, AVG(outcome_value) AS average_outcome_value
FROM trial_outcomes
GROUP BY outcome_type;

SELECT COUNT(DISTINCT participant_id) AS participant_count
FROM trial_adverse_events
WHERE event_type IN ('Mild', 'Moderate');

SELECT location_name, city, state
FROM trial_locations
ORDER BY city, state;

SELECT COUNT(participant_id) AS number_of_participants, trial_id
FROM trial_participants
GROUP BY trial_id;

SELECT COUNT(DISTINCT participant_id) AS resolved_adverse_event_participants
FROM trial_adverse_events
WHERE resolution_date < '2010-05-01';

SELECT location_name, capacity
FROM trial_locations
WHERE regulatory_compliance = 1 AND capacity = (SELECT MAX(capacity) FROM trial_locations WHERE regulatory_compliance = 1);
